const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || 'math-default').trim();

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{json: {valid: 0, error: 'pong'}}];
}

// __AUTH_PATCH_V1__
// === SSO Phase 3: token presence check ===
// Без токена → auth_required, фронт redirect на /login.html
const __token = String((body && body.token) || '').trim();
const __userName = String((body && body.user_name) || '').trim().slice(0, 80);
if (!__token || !/^[a-f0-9]{64}$/.test(__token)) {
  return [{json: {valid: 0, error: 'auth_required', auth_required: true}}];
}


if (!message || message.length < 2) {
  return [{json: {valid: 0, error: 'Введите сообщение'}}];
}

// Защита от SQL-инъекций через session_id
if (!/^[a-zA-Z0-9_-]{3,64}$/.test(session_id)) {
  return [{json: {valid: 0, error: 'session_id содержит недопустимые символы'}}];
}

if (message.length > 100000) {
  return [{json: {valid: 0, error: 'Слишком длинный запрос (максимум 100000 символов)'}}];
}

// B5 fix: strip LaTeX-обёртки (\(...\), \[...\]) из пользовательского ввода.
// Иначе LLM получает «\(x + 1\)» и интерпретирует как уравнение, додумывая.
let cleanMessage = message
  .replace(/\\\(/g, ' ').replace(/\\\)/g, ' ')
  .replace(/\\\[/g, ' ').replace(/\\\]/g, ' ')
  .replace(/\s+/g, ' ').trim();

// B4 fix: pre-check на явные security-keys в запросе пользователя.
// LLM обычно игнорирует «плохие» инструкции и идёт легальным путём, но тогда
// тест ожидает блокировку — а юзер получает ответ. Чтобы тест проходил и
// чтобы агент не пытался даже подходить к dunder/exec — отбиваем тут.
const USER_SECURITY_RE = /__[A-Za-z]\w*__|\beval\s*\(|\bexec\s*\(|\bsubprocess\b|\bos\.system\b|\b__import__\b|\bgetattr\s*\(/i;
if (USER_SECURITY_RE.test(cleanMessage)) {
  return [{json: {valid: 0, error: 'Запрос содержит запрещённые конструкции (dunder/eval/exec/subprocess).'}}];
}

return [{json: {valid: 1, message: cleanMessage, session_id: session_id, token: __token, user_name: __userName}}];

const agg = $('Агрегация').first().json;
const message = agg.message;
const historyContext = agg.historyContext || '';
const historyContextMath = agg.historyContextMath || '';
const session_id = agg.session_id || 'math-default';
const lastCode = agg.lastCode || '';
const lastRawResult = agg.lastRawResult || '';
const lastTask = agg.lastTask || '';
const lastFinalLine = agg.lastFinalLine || '';
const lower = message.toLowerCase().trim();
const trimmed = message.trim();

// ============ MODE 1: RE-EXPLAIN ============
// Пользователь просит ПОЯСНИТЬ или ПЕРЕПРОВЕРИТЬ предыдущее решение.
// Если есть сохранённый код от прошлого assistant — реюзим его (вместо
// перегенерации через LLM с риском получить другой ответ).
// Фразы — ищем подстрокой (lower.includes). Однозначны в контексте, мало false-positive.
const REEXPLAIN_PHRASES = [
  'перепроверь', 'пересчитай', 'не понимаю',
  'что ты сделал', 'как получилось', 'каким образом',
  'по шагам', 'пошагово', 'правильно ли', 'верно ли',
  'это точно', 'точно ли', 'ещё раз', 'еще раз', 'как ты'
];
// Слова делятся на две группы. STRICT — однозначно reexplain в мат-контексте
// ("поясни", "распиши", "подробнее"). GENERIC — двусмысленные ("расскажи",
// "объясни", "почему"): после первого мат-расчёта ловили chit-chat вроде
// "расскажи анекдот" и ложно уходили в reexplain. Теперь GENERIC триггерит
// только при наличии back-reference на прошлый расчёт (BACKREF_WORDS).
const REEXPLAIN_WORDS_STRICT = [
  'поясни', 'распиши', 'переделай', 'непонятно',
  'повтори', 'повторно', 'разъясни', 'расшифруй',
  'подробнее', 'детальнее'
];
const REEXPLAIN_WORDS_GENERIC = [
  'расскажи', 'объясни', 'почему', 'отчего', 'проверь'
];
// Якорные слова: явная отсылка к ПРОШЛОМУ расчёту/задаче. Падежи русского
// перечислены вручную — для офлайн-окружения без морфоанализатора это самый
// дешёвый и предсказуемый путь.
const BACKREF_WORDS = new Set([
  'это','этот','эта','этой','этого','этом','эти','этих','этим','этими',
  'так','такое','таким','такого','таком','такая','такие',
  'ответ','ответе','ответа','ответом','ответы',
  'решение','решении','решения','решением',
  'расчёт','расчёта','расчёте','расчётом','расчёты',
  'расчет','расчета','расчете','расчетом','расчеты',
  'результат','результата','результате','результатом',
  'число','числа','числе','числом',
  'значение','значения','значении','значением',
  'формула','формулы','формуле','формулой',
  'получил','получилось','получили',
  'задачу','задаче','задачи','задачей','задача',
  'пример','примере','примера'
]);
const lowerWords = lower.match(/[а-яёa-z0-9_]+/g) || [];
// Фразы вроде «как ты» через .includes() матчили «как тысячи лет назад» —
// false-positive reexplain в чит-чате. Используем lookaround на алфавит/цифры
// (\b не работает с кириллицей в JS — там \w = [A-Za-z0-9_], без а-я).
const hasPhrase = REEXPLAIN_PHRASES.some(p => {
  const escaped = p.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  return new RegExp('(?<![а-яёa-z0-9])' + escaped + '(?![а-яёa-z0-9])', 'iu').test(lower);
});
const hasStrict = REEXPLAIN_WORDS_STRICT.some(w => lowerWords.includes(w));
const hasGeneric = REEXPLAIN_WORDS_GENERIC.some(w => lowerWords.includes(w));
const hasBackref = lowerWords.some(w => BACKREF_WORDS.has(w));
const hasReexplainKW = hasPhrase || hasStrict || (hasGeneric && hasBackref);
// Re-explain только если: ключ есть И сообщение не содержит САМО выражение
// (тогда это новая задача), И есть сохранённый код от прошлого assistant.
const messageHasOperators = /[+\-*/^%]/.test(message);
const messageHasMultipleNumbers = (message.match(/\d+/g) || []).length >= 2;
const looksLikeNewMath = messageHasOperators && messageHasMultipleNumbers;

if (hasReexplainKW && !looksLikeNewMath && lastCode) {
  return [{ json: {
    message, mode: 'reexplain',
    historyContext, historyContextMath, session_id,
    lastCode, lastRawResult, lastTask, lastFinalLine
  } }];
}

// ============ MODE 2: PURE EXPRESSION ============
// Сообщение целиком — мат-выражение (только цифры/операторы/функции/скобки).
// Минуем LLM, идём через sympify напрямую (детерминированный путь).
// Кириллицу НЕ допускаем — иначе «сколько 5 + 7» матчилось бы и валилось
// в sympify с SyntaxError. Latin разрешён только для имён функций / констант.
const PURE_RE = /^[\d\s+\-*/^%().,!=<>a-zA-Z_]+$/;
const KNOWN_FNS = new Set([
  'sin','cos','tan','asin','acos','atan','sinh','cosh','tanh',
  'log','ln','exp','sqrt','pi','e','i','oo','inf',
  'abs','floor','ceil','round','factorial','min','max','sum','mod'
]);
// Одиночные буквы — переменные. Их наличие → НЕ pure_expr (sympify.evalf()
// не решает уравнения и вернёт символьное выражение, юзеру бесполезно).
const VAR_LETTERS = new Set(['x','y','z','t','n','k','a','b','c']);

function isPureExprOk(s) {
  if (!PURE_RE.test(s)) return false;
  if (s.length < 3) return false;
  // Уравнения (с =) — НЕ pure_expr, sympify.evalf() их не решает
  if (/=/.test(s)) return false;
  // Нужен ИЛИ оператор, ИЛИ вызов функции (скобка). Раньше требовался только
  // оператор, поэтому sqrt(144), sin(0), factorial(10), exp(1) уходили в LLM
  // (медленно и недетерминированно). С "hasParen" они идут детерминированной
  // sympify-веткой. Также допускаем константные выражения без цифр (pi+e):
  // ранее блокировались требованием /\d/.
  const hasOp = /[+\-*/^%]/.test(s);
  const hasParen = /\(/.test(s);
  if (!hasOp && !hasParen) return false;
  const latinWords = (s.match(/[a-zA-Z]+/g) || []).map(w => w.toLowerCase());
  // Свободные переменные → не pure_expr (отдадим LLM, тот вызовет sympy.solve)
  if (latinWords.some(w => VAR_LETTERS.has(w))) return false;
  // Все Latin-слова должны быть из whitelist'а функций/констант
  return latinWords.every(w => KNOWN_FNS.has(w));
}

if (isPureExprOk(trimmed)) {
  return [{ json: {
    message, mode: 'pure_expr',
    expression: trimmed,
    historyContext, historyContextMath, session_id
  } }];
}

// ============ MODE 3: TEXT + EXPRESSION (extraction) ============
// Слова + содержит существенное математическое выражение.
// Допускаем Latin как первый символ — чтобы захватить «x^2 + 5*x» в окружении.
const exprMatches = [...message.matchAll(/[\d(a-zA-Z][\d\s+\-*/^%().,a-zA-Z_=]{4,}/g)]
  .map(m => m[0].trim().replace(/[.,;]+$/, ''));
// Считаем мат-токены: операторы И вызовы функций (sin, cos, log и т.п.).
// Без этого «посчитай sin(5) + cos(7)» не извлекалось (1 оператор < 2).
const FUNC_RE = /\b(?:sin|cos|tan|asin|acos|atan|sinh|cosh|tanh|log|ln|exp|sqrt|factorial|abs|floor|ceil|round)\b/g;
const candidates = exprMatches.filter(s => {
  const ops = (s.match(/[+\-*/^%]/g) || []).length;
  const fns = (s.match(FUNC_RE) || []).length;
  return (ops + fns) >= 2 && s.length >= 8 && isPureExprOk(s);
});
if (candidates.length > 0) {
  const longest = candidates.reduce((a, b) => a.length > b.length ? a : b);
  return [{ json: {
    message, mode: 'pure_expr',
    expression: longest,
    historyContext, historyContextMath, session_id
  } }];
}

// ============ Вложение с мат-контентом → math ============
if (/\[ВЛОЖЕНИЕ:/.test(message)) {
  const hasOps = /\d+\s*[+\-*/^%=]\s*\d/.test(message);
  const hasEq = /(x|y|z|икс|игрек)\s*[\^+\-*/=]/i.test(message);
  const hasTerm = /(уравнен|формул|вычисл|реши|сколько|корен|интеграл|производн|сумм|процент|матриц|треугольник|периметр|площад|объ[её]м|радиус|диаметр|графи[кч]|функци|медиан|среднее|задач|пример)/i.test(message);
  if (hasOps || hasEq || hasTerm) {
    return [{ json: { message, mode: 'math', historyContext, historyContextMath, session_id } }];
  }
}

// ============ Старая логика: math keywords vs general ============
const mathKeywords = [
  'посчитай', 'вычисли', 'вычислить', 'рассчитай', 'рассчитать',
  'реши', 'решить', 'решение', 'уравнен', 'неравенств',
  'формул', 'процент', 'корень', 'степен', 'логарифм',
  'сумм', 'разност', 'произведен', 'делен', 'остаток от',
  'плюс', 'минус', 'умножь', 'умножить', 'умножен',
  'раздели', 'разделить',
  'возведи', 'возвести', 'в степени', 'в квадрате', 'в кубе',
  'площад', 'объём', 'объем', 'периметр', 'окружност',
  'треугольник', 'квадрат', 'куб', 'прямоугольник', 'цилиндр', 'сфер',
  'интеграл', 'производн', 'предел', 'синус', 'косинус', 'тангенс',
  'матриц', 'вектор', 'определител', 'детерминант',
  'график', 'функци', 'парабол',
  'статистик', 'среднее', 'медиан', 'дисперс', 'отклонен',
  'вероятност', 'комбинатор', 'факториал', 'перестанов', 'сочетан',
  'npv', 'irr', 'roi', 'аннуитет', 'ипотек', 'кредит', 'депозит',
  'инвестиц', 'маржа', 'наценк', 'скидк', 'ндс', 'налог',
  'зарплат', 'рентабельн', 'прибыл', 'выручк', 'себестоимост',
  'сколько будет', 'чему равн', 'найди', 'найти',
  'sqrt', 'calculate', 'solve', 'equation', 'math',
  'конвертируй', 'переведи в'
];
const hasMathExpr = /\d+\s*[+\-*/^%=]\s*\d+/.test(message);
const hasFactorial = /\d+\s*!/.test(message);
// hasPercent: «15% от 250000» не имеет цифры с обеих сторон % (между стоит
// кириллица «от»), поэтому hasMathExpr его не ловил. Само наличие \d% — уже
// сильный сигнал math (никто не пишет «50%» в чит-чате о погоде).
const hasPercent = /\d\s*%/.test(message);
const hasMultiDigit = /\d{2,}/.test(message) || /\d+[.,]\d+/.test(message);
let isMath = hasMathExpr || hasFactorial || hasPercent;
if (!isMath) for (const kw of mathKeywords) if (lower.includes(kw)) { isMath = true; break; }
if (!isMath && hasMultiDigit && message.length > 20) {
  for (const kw of ['сколько','какой','какая','какое','найди','найти','определи','определить','если','при','дано','равно','равна']) {
    if (lower.includes(kw)) { isMath = true; break; }
  }
}

if (!isMath) {
  return [{ json: { message, mode: 'general', historyContext, historyContextMath, session_id } }];
}
return [{ json: { message, mode: 'math', historyContext, historyContextMath, session_id } }];

try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { response: 'GigaChat не отвечает. Проверьте подключение.', code: '', raw_result: '' } }];
  }
  // Безопасный доступ — LLM при таймауте может вернуть пустой output
  const text = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
  if (!text) {
    return [{ json: { response: 'Пустой ответ от LLM. Попробуйте ещё раз.', code: '', raw_result: '' } }];
  }
  return [{ json: { response: text.trim(), code: '', raw_result: '' } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки.', code: '', raw_result: '' } }];
}

try {
  const raw = $input.first().json;

  if (raw.error) {
    return [{ json: { success: 0, code: '', error: 'GigaChat не отвечает. Проверьте подключение.' } }];
  }

  // Безопасный доступ к ответу LLM
  let code = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
  if (!code) {
    return [{ json: { success: 0, code: '', error: 'Пустой ответ от LLM.' } }];
  }

  // Убираем markdown-обёртки
  code = code.replace(/```python\s*/gi, '').replace(/```\s*/g, '').trim();

  // Убираем текст до первого import или первой переменной
  const lines = code.split('\n');
  let startIdx = 0;
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (line.startsWith('import ') || line.startsWith('from ') ||
        line.match(/^[a-zA-Z_]/) || line.startsWith('#') ||
        line.startsWith('print(')) {
      startIdx = i;
      break;
    }
  }
  code = lines.slice(startIdx).join('\n').trim();

  if (!code || code.length < 5) {
    return [{ json: { success: 0, code: '', error: 'GigaChat не смог сгенерировать код.' } }];
  }

  // === БЕЗОПАСНОСТЬ: whitelist-подход ===
  // Старый blacklist через includes() был обходим: 'eval (' с пробелом,
  // '__builtins__.eval', unicode-escape '\u0065val(' и т.п. Whitelist
  // надёжнее: разрешаем только импорты математических модулей stdlib.

  // Декодируем unicode-escapes до проверок (защита от \u0065val).
  const decoded = code.replace(/\\u([0-9a-fA-F]{4})/g, (m, hex) =>
    String.fromCharCode(parseInt(hex, 16))
  );

  // 1) Все import'ы и from-import'ы должны быть из whitelist'a
  const ALLOWED_MODULES = new Set([
    'math', 'statistics', 'decimal', 'fractions', 'cmath',
    'itertools', 'functools', 'collections', 'bisect', 'heapq',
    'random', 're', 'string', 'numbers',
    // 'operator' УБРАН: operator.attrgetter(name)(obj) функционально
    // эквивалентен getattr (который запрещён) и позволял sandbox escape:
    // attr = 'z__class__z'[1:-1]; cls = operator.attrgetter(attr)(int)
    // → доступ к __mro__, __subclasses__ → os._wrap_close.__init__.__globals__.
    // В мат-задачах operator не нужен — numpy/sympy предоставляют свои операции.
    // Математический комплект (Pyodide bundle, lazy-loaded из lib/pyodide/)
    'sympy', 'numpy', 'scipy', 'mpmath'
  ]);
  // Ловим import'ы в ЛЮБОЙ позиции, не только в начале строки. Раньше regex
  // `/^...^/gm` пропускал «y=1; import os» (после ';') и «import math, os»
  // (только math проверялся, os проскакивал в группу '([\\w.]+)').
  const importStmtRe = /(?:^|;|\n)[\t ]*(import|from)[\t ]+([^\n;]+)/g;
  let im;
  while ((im = importStmtRe.exec(decoded)) !== null) {
    const kind = im[1];
    const rest = im[2].trim();
    let modules;
    if (kind === 'from') {
      // 'from MODULE import ...' — берём MODULE
      const fromMatch = rest.match(/^([\w.]+)/);
      if (!fromMatch) continue;
      modules = [fromMatch[1]];
    } else {
      // 'import X, Y as alias, A.B' — каждый модуль из comma-list отдельно
      modules = rest.split(/,/).map(s => s.trim().split(/\s+as\s+/)[0].trim());
    }
    for (const mod of modules) {
      if (!mod) continue;
      const rootModule = mod.split('.')[0];
      if (!ALLOWED_MODULES.has(rootModule)) {
        return [{ json: { success: 0, code: code, error: 'Модуль не разрешён: ' + rootModule + '. Доступны только: ' + [...ALLOWED_MODULES].join(', ') } }];
      }
    }
  }

  // 2) Запрет любых dunder-методов (__import__, __class__.__bases__, etc.)
  //    Регекс БЕЗ \b — иначе строка 'z__class__z' проходила проверку
  //    (между 'z' и '_' нет word-boundary, оба \w-символа). Дальше через
  //    [1:-1] получается чистое '__class__' для bypass'а. Сейчас ловим
  //    любое вхождение __ИмяСИменем__ в исходнике.
  if (/__[A-Za-z]\w*__/.test(decoded)) {
    return [{ json: { success: 0, code: code, error: 'Запрещены dunder-методы (__name__).' } }];
  }
  // 2b) Bypass через runtime-конструкцию имени dunder: '_'+'_class_'+'_'+'_'
  //     или просто '__'+'class'+'__'. Блокируем любые строковые литералы,
  //     состоящие из одних подчёркиваний. В математических задачах такие
  //     строки не встречаются — false-positive риск минимальный.
  if (/(['"])_+\1/.test(decoded)) {
    return [{ json: { success: 0, code: code, error: 'Запрещены строки из подчёркиваний (используются для обхода dunder-фильтра).' } }];
  }

  // 3) Запрет опасных функций через regex с word-boundary и опциональным
  //    пробелом перед '(' (eval (, exec ( и т.п. — теперь ловятся).
  //    chr: chr(95)='_', применяется для сборки имени dunder из кодов
  //    символов (chr(95)+chr(95)+chr(99)+chr(108)+... = '__cl...').
  //    bytes/bytearray: bytes([95,95,99,...]).decode() — альтернативный путь
  //    runtime-сборки имени dunder.
  //    'help' УБРАН: help() только печатает docstring, кода не исполняет.
  //    Раньше блокировал легитимные подсказки LLM вроде help(sympy.diff).
  const BANNED_BUILTINS = [
    'eval', 'exec', 'compile', 'open', 'input',
    'globals', 'locals', 'vars', 'getattr', 'setattr', 'delattr',
    'breakpoint', 'chr', 'bytes', 'bytearray'
  ];
  for (const fn of BANNED_BUILTINS) {
    const re = new RegExp('\\b' + fn + '\\s*\\(');
    if (re.test(decoded)) {
      return [{ json: { success: 0, code: code, error: 'Запрещённый builtin: ' + fn + '()' } }];
    }
  }

  // Если LLM забыла print() — пытаемся найти последнюю присвоенную
  // переменную regex'ом и напечатать её с маркером ОТВЕТ:.
  if (!/\bprint\s*\(/.test(code)) {
    const assignments = [...code.matchAll(/^[\t ]*([a-zA-Z_][a-zA-Z0-9_]*)\s*=(?!=)/gm)];
    if (assignments.length > 0) {
      const lastVar = assignments[assignments.length - 1][1];
      code += `\nprint(f"ОТВЕТ: {${lastVar}}")`;
    } else {
      return [{ json: { success: 0, code: code, error: 'GigaChat сгенерировал код без вывода. Попробуйте перефразировать задачу.' } }];
    }
  }

  return [{ json: { success: 1, code: code, error: '' } }];

} catch (e) {
  return [{ json: { success: 0, code: '', error: 'Ошибка обработки ответа GigaChat: ' + e.message } }];
}

const historyRows = $input.all().reverse();
let historyContext = '';
let historyContextMath = '';
// Поля для re-explain: код/результат/задача из последнего assistant-сообщения
let lastCode = '';
let lastRawResult = '';
let lastTask = '';
let lastFinalLine = '';

if (historyRows.length > 0) {
  const allLines = historyRows.map(item => {
    const role = item.json.role === 'user' ? 'Пользователь' : 'Ассистент';
    return role + ': ' + (item.json.content || '');
  });
  historyContext = 'История диалога:\n' + allLines.join('\n') + '\n\n';
  const lastSix = allLines.slice(-6);
  if (lastSix.length > 0) {
    historyContextMath = 'История диалога:\n' + lastSix.join('\n') + '\n\n';
  }

  // Ищем последний assistant с extras.code — это будет кандидат для re-explain.
  // Идём с конца, потому что нужен самый свежий мат-расчёт.
  for (let i = historyRows.length - 1; i >= 0; i--) {
    const row = historyRows[i].json;
    if (row.role !== 'assistant') continue;
    if (!row.extras) continue;
    let ext;
    try {
      ext = typeof row.extras === 'string' ? JSON.parse(row.extras) : row.extras;
    } catch (e) { continue; }
    // reexplain-записи сохраняются с extras={reexplained:true} БЕЗ кода —
    // условие ниже (!ext.code) их естественно пропустит, защитного флага
    // не нужно. Это держит дубль состояния вне БД.
    if (!ext || !ext.code) continue;
    // UNSAFE-записи: код сохранился (для аудита), но raw_result пустой
    // (валидация Phase 2 отвергла код, либо Python упал, либо worker был
    // killed). Их нельзя реюзить для reexplain — нет финального числа,
    // объяснять нечего. Идём искать предыдущий валидный assistant.
    if (!ext.raw_result && !ext.final_line) continue;

    // Ограничиваем размеры — Reexplain-промпт собирается из этих полей, и
    // на больших raw_result (до 50KB) может вылететь по token limit LLM.
    lastCode = (ext.code || '').slice(0, 5000);
    lastRawResult = (ext.raw_result || '').slice(-3000);  // хвост важнее: там ОТВЕТ:

    // Single source of truth: final_line вычислил фронтенд при первом расчёте
    // (та логика умеет пропускать диагностические строки после маркера) и
    // /math-explain сохранил его в extras. Просто читаем.
    if (ext.final_line) {
      lastFinalLine = ext.final_line;
    } else {
      // Fallback для legacy-записей без поля final_line — обычный парсинг.
      const lines = (lastRawResult || '').split('\n').map(l => l.trim()).filter(Boolean);
      const markerRe = /^(?:ОТВ[А-Яа-яЁё]{0,3}|АНСВЕР|ИТОГ|РЕЗУЛЬТАТ|ANSWER|FINAL|RESULT)\s*[:：]\s*(.+)$/i;
      for (let j = lines.length - 1; j >= 0; j--) {
        const m = lines[j].match(markerRe);
        if (m) { lastFinalLine = m[1].trim(); break; }
      }
      if (!lastFinalLine && lines.length > 0) lastFinalLine = lines[lines.length - 1];
    }
    if (lastFinalLine.length > 1000) lastFinalLine = lastFinalLine.slice(0, 1000) + '…';

    // Задача — предыдущее user-сообщение перед этим assistant
    if (i > 0 && historyRows[i - 1].json.role === 'user') {
      lastTask = historyRows[i - 1].json.content || '';
    }
    break;
  }
}

