// Сборка финального ответа MATH детерминированно:
//   число берём из final_line (= вывод Pyodide), пояснение — от LLM.
// Если Pyodide сломался (exec_error не пустой), возвращаем ошибку и не
// дёргаем LLM-пояснение как итог — оно не имеет смысла без результата.
try {
  const raw = $input.first().json;
  const prev = $('Извлечение полей').first().json;

  // Серверная валидация Phase 2 отклонила запрос (session_id, длина и т.п.).
  // Контракт: Извлечение полей при отказе возвращает {error: '...'} вместо
  // полей. Прежде Сборка это игнорировала и выдавала ложное «Код выполнился,
  // но не вернул значение».
  if (prev.error) {
    return [{ json: { response_text: 'Запрос отклонён: ' + prev.error } }];
  }

  // Pyodide убит по таймауту (worker.terminate с фронта) — exec_error уже
  // содержит user-friendly сообщение от PyodideClient, не оборачиваем.
  if (prev.exec_killed) {
    return [{ json: { response_text: prev.exec_error || 'Python был прерван по таймауту.' } }];
  }

  // Python-исключение (ModuleNotFoundError, SyntaxError, ZeroDivisionError
  // и т.п.) — оборачиваем в понятный префикс.
  if (prev.exec_error) {
    return [{ json: { response_text: 'Не удалось решить — Python завершился с ошибкой:\n' + prev.exec_error } }];
  }

  const finalLine = (prev.final_line || prev.raw_result || '').trim();
  if (!finalLine) {
    return [{ json: { response_text: 'Код выполнился, но не вернул значение.' } }];
  }

  // Извлекаем пояснение LLM (может быть отсутствует — таймаут / GigaChat недоступен)
  let explanation = '';
  try {
    explanation = raw.output[0].content[0].text.trim();
  } catch (e) {
    explanation = '';
  }

  // Защита: если LLM всё-таки начала с «Ответ: ...» — срезаем эту шапку,
  // чтобы не было дубликата числа в финальном ответе.
  explanation = explanation
    .replace(/^Ответ\s*[:\-]\s*[^\n.]+[.\n]\s*/i, '')
    .replace(/^Итак[,]?\s*получаем[^\n.]+[.\n]\s*/i, '')
    .trim();

  let response = 'Ответ: ' + finalLine;
  if (explanation) {
    response += '\n\n' + explanation;
  }

  return [{ json: { response_text: response } }];
} catch (e) {
  const prev = $('Извлечение полей').first().json;
  if (prev && prev.final_line) {
    return [{ json: { response_text: 'Ответ: ' + prev.final_line } }];
  }
  if (prev && prev.raw_result) {
    return [{ json: { response_text: 'Ответ: ' + prev.raw_result } }];
  }
  return [{ json: { response_text: 'Ошибка обработки.' } }];
}

// PURE_EXPR: генерируем sympify-код БЕЗ LLM. Детерминированный путь:
//   на одно и то же выражение всегда один и тот же код → один и тот же ответ.
// parse_expr с transformations:
//   convert_xor — превращает `^` в `**` (Python степень)
//   implicit_multiplication_application — позволяет писать `2x` вместо `2*x`
const data = $input.first().json;
let raw = (data.expression || data.message || '').trim();

// Русская десятичная запятая → точка ТОЛЬКО для изолированных пар d,d.
// Сценарии:
//   «10,5»        → «10.5»  (десятичная)
//   «f(x, y)»     → не трогаем (пробел)
//   «(1,2,3)»     → не трогаем (цепочка d,d,d — кортеж/аргументы)
//   «f(0,5, 1,5)» → «f(0.5, 1.5)» (2 изолированных пары, разделённых пробелом)
// Lookbehind (?<!\d,) и lookahead (?!,\d) гарантируют, что мы НЕ внутри цепочки.
raw = raw.replace(/(?<!\d,)(\d),(\d)(?!,\d)/g, '$1.$2');

// Препроцесс: «mod» как оператор остатка → «%». Без этого «123 mod 7»
// парсится как «123 * mod * 7» (mod — свободный символ), .evalf() оставляет
// символическое выражение. С % parse_expr корректно делает Mod(123, 7).
// Окружения проверяем чтобы НЕ трогать слова типа «model», «modify».
raw = raw.replace(/(\d)\s+mod\s+(\d)/gi, '$1 % $2');

// Экранирование для встраивания в Python-строку
const esc = raw.replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, ' ');

const code = [
  'from sympy.parsing.sympy_parser import parse_expr, standard_transformations, convert_xor, implicit_multiplication_application',
  'from sympy import log, ln, sin, cos, tan, asin, acos, atan, exp, sqrt, pi, E, I, oo, factorial, Rational, ceiling, floor, Abs, simplify, Float',
  'transformations = standard_transformations + (convert_xor, implicit_multiplication_application)',
  '# local_dict — мэппинг ИМЁН ИЗ ВЫРАЖЕНИЯ на sympy-сущности.',
  '#   e (lowercase) → E (Euler) — иначе \'pi + e\' оставался бы pi + free_symbol(e)',
  '#   ceil/floor/abs → sympy.ceiling/floor/Abs — иначе \'ceil(3.2)\' с',
  '#     implicit_multiplication парсилось как c*e*i*l*(3.2).',
  '#   ln → log (sympy.log это натуральный, ln в sympy alias на log).',
  'local_dict = {',
  '    "e": E, "E": E, "pi": pi, "Pi": pi,',
  '    "ceil": ceiling, "floor": floor, "abs": Abs,',
  '    "ln": log,  # натуральный',
  '}',
  `expr_str = "${esc}"`,
  'try:',
  '    expr = parse_expr(expr_str, transformations=transformations, local_dict=local_dict)',
  '    # simplify() сворачивает log(exp(x)) → x, упрощает тригонометрию,',
  '    # raises tan(arctan(x)) → x. Без simplify результат остался бы символическим.',
  '    simplified = simplify(expr)',
  '    # evalf() приводит к числу с произвольной точностью (default 15 знаков).',
  '    result = simplified.evalf()',
  '    # Если результат всё ещё символический (например имена переменных в выражении) —',
  '    # выводим как есть. Иначе округляем до 6 значащих, чтобы не вываливать 15 цифр.',
  '    try:',
  '        if result.is_number:',
  '            # B1 fix: целые числа (factorial(15) = 1307674368000) выводим',
  '            # как integer без потери точности. .10g формат даёт scientific',
  '            # для целых > 10^10 (1.307674368e+12) — теряет последние нули.',
  '            if result.is_integer:',
  '                result_str = str(int(result))',
  '            else:',
  '                result_float = float(result)',
  '                # round до 6 значащих знаков, без trailing-нулей',
  '                if abs(result_float) >= 1e-4 and abs(result_float) < 1e15:',
  '                    result_str = f"{result_float:.10g}"',
  '                else:',
  '                    result_str = str(result)',
  '        else:',
  '            result_str = str(result)',
  '    except Exception:',
  '        result_str = str(result)',
  '    # ** → ^ для математической нотации в выводе. Внутри Python используется **,',
  '    # но юзер ожидает видеть ^. expr_str показывает «Выражение» как ввёл юзер,',
  '    # str(simplified) может содержать ** в символьной части.',
  '    expr_display = str(simplified).replace("**", "^")',
  '    result_display = result_str.replace("**", "^")',
  '    print(f"Выражение: {expr_display}")',
  '    print(f"ОТВЕТ: {result_display}")',
  'except Exception as e:',
  '    print(f"Не удалось распознать выражение: {e}")',
  '    print(f"ОТВЕТ: ошибка парсинга")'
].join('\n');

// Возвращаем в LLM-формате: «Проверка кода» ожидает raw.output[0].content[0].text
// (она спроектирована под выход LLM-узла «Генерация кода»). Без обёртки
// pure_expr-ветка вернёт «Пустой ответ от LLM».
return [{ json: { output: [{ content: [{ text: code }] }] } }];

